import pandas as pd

def answer_question(df):
    """
    Analyzes the DataFrame to find the national park with the highest visitor spending.

    Args:
        df (pd.DataFrame): A DataFrame with 'Park Name' and 'Visitor Spending (USD)' columns.

    Returns:
        str: The name of the national park with the highest visitor spending.
    """
    if df.empty:
        return "No data available."

    # Find the row with the maximum visitor spending
    highest_spending_park = df.loc[df['Visitor Spending (USD)'].idxmax()]

    return highest_spending_park['Park Name']

